type DataContext = Record<string, any>;

function createFormulaEvaluator(): (template: string, data: DataContext) => string {
  return function evaluate(template: string, data: DataContext): string {
    return template.replace(/\{\{(.*?)\}\}/g, (_match, expression: string) => {
      const trimmedExpr = expression.trim();
      try {
        // Build a function that has all data keys available as local variables
        const keys = Object.keys(data);
        const values = keys.map(k => data[k]);

        // Create a function with the data properties as parameters
        const fn = new Function(...keys, `return (${trimmedExpr});`);
        const result = fn(...values);

        return result !== undefined && result !== null ? String(result) : '';
      } catch (e) {
        return `{{ERROR: ${(e as Error).message}}}`;
      }
    });
  };
}

// Export the factory function and a convenience direct function
export { createFormulaEvaluator };

export function evaluateTemplate(template: string, data: DataContext): string {
  const evaluator = createFormulaEvaluator();
  return evaluator(template, data);
}

// Demo / test
if (require.main === module) {
  const evaluate = createFormulaEvaluator();

  const data = {
    price: 29.99,
    quantity: 3,
    name: "Widget",
    discount: 0.1,
    tax: 0.08,
    items: [{ name: "A" }, { name: "B" }],
  };

  // Basic multiplication
  console.log(evaluate("Total: {{price * quantity}}", data));
  // => "Total: 89.97"

  // String interpolation
  console.log(evaluate("Product: {{name}}", data));
  // => "Product: Widget"

  // Complex expression with discount and tax
  console.log(
    evaluate(
      "Final: {{(price * quantity * (1 - discount) * (1 + tax)).toFixed(2)}}",
      data
    )
  );
  // => "Final: 87.39"

  // Ternary / conditional
  console.log(
    evaluate("Status: {{quantity > 0 ? 'In Stock' : 'Out of Stock'}}", data)
  );
  // => "Status: In Stock"

  // Array access
  console.log(evaluate("First item: {{items[0].name}}", data));
  // => "First item: A"

  // Mixed text with multiple expressions
  console.log(
    evaluate(
      "Invoice: {{quantity}}x {{name}} @ ${{price.toFixed(2)}} each = ${{(price * quantity).toFixed(2)}}",
      data
    )
  );
  // => "Invoice: 3x Widget @ $29.99 each = $89.97"

  // Math functions
  console.log(evaluate("Rounded: {{Math.round(price)}}", data));
  // => "Rounded: 30"

  // Error handling
  console.log(evaluate("Bad: {{undefinedFunc()}}", data));
  // => "Bad: {{ERROR: ...}}"

  // No expressions - passthrough
  console.log(evaluate("Plain text, no formulas", data));
  // => "Plain text, no formulas"
}

