        // Create a function with the data keys as parameters and evaluate the expression
        const fn = new Function(...keys, `return (${trimmedExpr});`);
        const result = fn(...values);

        return result !== undefined && result !== null ? String(result) : '';
      } catch (e) {
        return `{{ERROR: ${trimmedExpr}}}`;
      }
    });
  };
}

