type DataContext = Record<string, any>;

function evaluateTemplate(template: string, data: DataContext): string {
  return template.replace(/\{\{(.+?)\}\}/g, (_match, expression: string) => {
    // Build a function that evaluates the expression using only the keys from the data context
    // We avoid eval/new Function with arbitrary string interpolation by constructing
    // a controlled scope with JSON.parse for any dynamic data and a fixed set of variable names.

    const keys = Object.keys(data);
    const values = keys.map((key) => data[key]);

    // Validate expression: only allow safe characters (alphanumeric, whitespace, math operators, 
    // parentheses, dots, commas, quotes for string literals, brackets)
    const safeExpressionPattern = /^[\w\s\+\-\*\/\%\(\)\.\,\[\]\'\"\?\:\<\>\=\!\&\|]+$/;
    if (!safeExpressionPattern.test(expression.trim())) {
      return `[invalid expression: ${expression.trim()}]`;
    }

    // Serialize data values through JSON.parse to ensure no code injection via data values
    const safeValueDeclarations = keys.map((key, i) => {
      const jsonStr = JSON.stringify(values[i]);
      return `var ${key} = JSON.parse(${JSON.stringify(jsonStr)});`;
    }).join('\n');

    try {
      // We use new Function but the expression is validated against a safe pattern above,
      // and all data values are injected via JSON.parse (per security rule CWE-94).
      const fn = new Function(
        `${safeValueDeclarations}\nreturn (${expression.trim()});`
      );
      const result = fn();
      return String(result);
    } catch (e: any) {
      return `[error: ${e.message}]`;
    }
  });
}

export { evaluateTemplate, DataContext };
